mapper.delete:
delete from ${prefix}ACT_HI_VAR_TRACE
where VAR_SCOPE_ID_ = #{variableScopeId, jdbcType=NVARCHAR}
  and VAR_SCOPE_TYPE_ = #{variableScopeType, jdbcType=VARCHAR}

mapper.select:
